prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName (COUNT(DISTINCT ?msgFlow) AS ?messageCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  ?task a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        tai:belongsTo ?choreo .

  # Task is connected to message flows via its message content endpoints
  ?msgFlow a bboExt:MessageFlow ;
           tai:belongsTo ?choreo ;
           bboExt:sourceRef ?srcRef ;
           bboExt:targetRef ?tgtRef .

  FILTER(
    STRENDS(STR(?srcRef), CONCAT("#", bbo:id, "")) ||
    STRENDS(STR(?tgtRef), CONCAT("#", bbo:id, ""))
  )
}
GROUP BY ?task ?taskName
HAVING(?messageCount = 2)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msg ?msgName ?choreo ?srcRef ?tgtRef WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model ;
        tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?msg a bboExt:MessageFlow ;
       tai:belongsTo ?choreo ;
       bboExt:sourceRef ?srcRef ;
       bboExt:targetRef ?tgtRef .
  OPTIONAL { ?msg bbo:name ?msgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msg ?srcRef ?tgtRef ?taskName ?choreoName WHERE {
  ?msg a bboExt:MessageFlow .

  ?msg tai:belongsTo ?choreo .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?msg bboExt:sourceRef ?srcRef ;
       bboExt:targetRef ?tgtRef .

  # Find tasks whose element identifiers match the message flow endpoint refs
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:id ?taskId ;
        bbo:name ?taskName .
  FILTER(
    STRENDS(STR(?taskId), STR(?srcRef)) ||
    STRENDS(STR(?taskId), STR(?tgtRef))
  )

  # constrain to model
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
}
LIMIT 25
